#[test]
fn test_compose_profiles_forwarded_to_command() {
    let project = ComposeProject {
        name: "test".to_string(),
        base_path: PathBuf::from("/tmp"),
        compose_files: vec![PathBuf::from("docker-compose.yml")],
        service: "app".to_string(),
        run_services: vec![],
        env_files: vec![],
        additional_mounts: vec![],
        profiles: vec!["dev".to_string(), "debug".to_string()],
        additional_env: IndexMap::new(),
        external_volumes: vec![],
    };
    let cmd = ComposeCommand::new(project.base_path.clone(), project.compose_files.clone())
        .with_profiles(project.profiles.clone());
    let built = cmd.build_command("up");
    let args: Vec<String> = built.get_args().map(|a| a.to_string_lossy().to_string()).collect();
    let profile_count = args.iter().filter(|a| a.as_str() == "--profile").count();
    assert_eq!(profile_count, 2);
}

#[test]
fn test_compose_no_profiles_no_flags() {
    let cmd = ComposeCommand::new(PathBuf::from("/tmp"), vec![PathBuf::from("docker-compose.yml")])
        .with_profiles(vec![]);
    let built = cmd.build_command("up");
    let args: Vec<String> = built.get_args().map(|a| a.to_string_lossy().to_string()).collect();
    assert!(!args.contains(&"--profile".to_string()));
}

#[tokio::test]
async fn test_uid_update_skipped_for_root() {
    let mock = MockUserMapper::new();
    mock.set_current_user(UserInfo::new("root".to_string(), 0, 0, "/root".to_string(), "/bin/sh".to_string()));
    let service = UserMappingService::new(mock);
    let config = UserMappingConfig::new(Some("root".to_string()), None, true)
        .with_host_user(0, 0);
    let result = service.apply_user_mapping("container123", &config).await.unwrap();
    assert!(!result.uid_updated, "Root user UID should never be modified");
}

#[tokio::test]
async fn test_uid_update_skipped_when_already_matching() {
    let mock = MockUserMapper::new();
    mock.set_user_info("vscode", UserInfo::new("vscode".to_string(), 1000, 1000, "/home/vscode".to_string(), "/bin/bash".to_string()));
    let service = UserMappingService::new(mock);
    let config = UserMappingConfig::new(Some("vscode".to_string()), None, true)
        .with_host_user(1000, 1000);
    let result = service.apply_user_mapping("container123", &config).await.unwrap();
    assert!(!result.uid_updated, "UID already matches, should skip update");
}

#[tokio::test]
async fn test_uid_update_skipped_when_disabled() {
    let mock = MockUserMapper::new();
    let service = UserMappingService::new(mock);
    let config = UserMappingConfig::new(Some("vscode".to_string()), None, false);
