#[test]
fn test_no_features_skips_build() {
    let config = DevContainerConfig {
        image: Some("ubuntu:22.04".to_string()),
        features: serde_json::Value::Null,
        ..Default::default()
    };
    let has_features = config.features
        .as_object()
        .map(|o| !o.is_empty())
        .unwrap_or(false);
    assert!(!has_features, "Null features should not trigger build");
}

#[test]
fn test_empty_features_skips_build() {
    let config = DevContainerConfig {
        image: Some("ubuntu:22.04".to_string()),
        features: serde_json::json!({}),
        ..Default::default()
    };
    let has_features = config.features
        .as_object()
        .map(|o| !o.is_empty())
        .unwrap_or(false);
    assert!(!has_features, "Empty features object should not trigger build");
}
